Call dlopen(..., RTLD_NOW) returns "Undefined symbol" when shared object 
uses a symbol from main program.

How-To-Repeat: 
Makefile
----------- begin Makefile -----------

prog: lib.so main.c
        gcc -g -fpic -DPIC -Wall -o prog main.c

lib.so: lib.c
        gcc -fpic -DPIC -O -pipe -Wall -c lib.c
        cc -shared -o lib.so lib.o

clean:
        rm -f prog *.o *.so
----------- end Makefile ---------------

main.c

----------- begin main.c ---------------
#include <stdio.h>
#include <sys/types.h>
#include <dlfcn.h>

char *str = "ok";

int main() {
        static void * lib_so;
        static void (*lib_so_func)();

        lib_so = dlopen("./lib.so", RTLD_NOW | RTLD_GLOBAL);
        if (!lib_so) {
                fprintf(stderr, "dlopen: %s\n", dlerror());
                return 1;
        }
        lib_so_func = dlsym(lib_so, "lib_so_func");
        if (!lib_so_func) {
                fprintf(stderr, "dlsym: %s\n", dlerror());
                return 1;
        }
        lib_so_func();

        return 0;
}

----------- end main.c ------------

lib.c

----------- begin lib.c -----------
#include <stdio.h>

extern char *str;

int lib_so_func() {
        printf("%s\n", str);
        return 1;
}
----------- end lib.c -----------

